export type EnrichmentActionCategory = "bootstrap-allure" | "narrow-test-scope" | "repair-test-metadata" | "add-meaningful-steps" | "add-test-attachments" | "add-retry-diagnostics" | "collapse-low-signal-trace" | "review-manually";
